using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the training service and train the model at startup
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train model before accepting requests
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndSave();

// Register PredictionEnginePool after model is saved
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider isn't possible after Build(), so we register it before Build().
// Let's restructure:
app.MapControllers();
app.Run();

